#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 2e5+5;
int n,B,Q,a[N];
int L[N],R[N],bel[N],cnt[N],to[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    n=read(),B=sqrt(n);
    for(int i=1;i<=n;i++)a[i]=read();
    for(int i=1;i<=B;i++)
        L[i]=R[i-1]+1,R[i]=R[i-1]+B;
    if(R[B]<n)++B,L[B]=R[B-1]+1,R[B]=n;
    for(int i=1;i<=B;i++)
        for(int x=L[i];x<=R[i];x++)bel[x]=i;
    for(int i=n;i>=1;i--){
        int nxt=i+a[i];
        if(nxt>R[bel[i]])cnt[i]=1,to[i]=nxt;
        else cnt[i]=cnt[nxt]+1,to[i]=to[nxt];
    }
    Q=read();
    while(Q--){
        int opt=read();
        if(opt==1){
            int x=read()+1,ans=0;
            while(x<=n)ans+=cnt[x],x=to[x];
            cout<<ans<<"\n";
        }else{
            int x=read()+1,k=read();a[x]=k;
            for(int i=R[bel[x]];i>=L[bel[x]];i--){
                int nxt=i+a[i];
                if(nxt>R[bel[i]])cnt[i]=1,to[i]=nxt;
                else cnt[i]=cnt[nxt]+1,to[i]=to[nxt];
            }
        }
    }
    return 0;
}
